fn eval_input_aggregate(
    input: &InputTable,
    agg: &Aggregate,
    params: &ParamEnv,
    result_rows: usize,
    result_type: &RuntimeType,
) -> Result<InternalColumn, EvalError> {
    let mut selected = Vec::with_capacity(input.row_count);
    for row in 0..input.row_count {
        let keep = match &agg.filter {
            Some(filter) => match eval_input_scalar(filter, input, row, params)? {
                InputScalar::Bool(value) => value,
                _ => return Err(EvalError::new("input aggregate filter is not Bool")),
            },
            None => true,
        };
        selected.push(keep);
    }
    match &agg.op {
        AggOp::Count => {
            let count = selected.iter().filter(|value| **value).count();
            let count = i64::try_from(count)
                .map_err(|_| EvalError::new("input aggregate count exceeds i64"))?;
            Ok(InternalColumn::Int(vec![count; result_rows]))
        }
        AggOp::Sum { value } => {
            // Level-A schedule shared with CUDA: ascending rows in two fixed
            // contiguous halves, then partial 0 followed by partial 1.
            let midpoint = input.row_count / 2;
            match result_type {
                RuntimeType::Real => {
                    let mut partials = [0.0_f64; 2];
                    for (partial, range) in [0..midpoint, midpoint..input.row_count]
                        .into_iter()
                        .enumerate()
                    {
                        for row in range {
                            if !selected[row] {
                                continue;
                            }
                            match eval_input_scalar(value, input, row, params)? {
                                InputScalar::Int(value) => partials[partial] += value as f64,
                                InputScalar::Real(value) => partials[partial] += value,
                                _ => {
                                    return Err(EvalError::new(
                                        "input aggregate Sum value is not numeric",
                                    ))
                                }
                            }
                        }
                    }
                    Ok(InternalColumn::Real(vec![
                        partials[0] + partials[1];
                        result_rows
                    ]))
                }
                RuntimeType::Int => {
                    let mut partials = [0_i64; 2];
                    for (partial, range) in [0..midpoint, midpoint..input.row_count]
                        .into_iter()
                        .enumerate()
                    {
                        for row in range {
                            if !selected[row] {
                                continue;
                            }
                            let InputScalar::Int(value) =
                                eval_input_scalar(value, input, row, params)?
                            else {
                                return Err(EvalError::new(
                                    "input aggregate Sum value is not numeric",
                                ));
                            };
                            partials[partial] =
                                partials[partial].checked_add(value).ok_or_else(|| {
                                    EvalError::new(format!(
                                        "input aggregate integer overflow at row {row}"
                                    ))
                                })?;
                        }
                    }
                    let sum = partials[0].checked_add(partials[1]).ok_or_else(|| {
                        EvalError::new("input aggregate integer overflow while merging partials")
                    })?;
                    Ok(InternalColumn::Int(vec![sum; result_rows]))
                }
                _ => Err(EvalError::new("input aggregate Sum has non-numeric type")),
            }
        }
    }
}

