                    )
                    .unwrap();
                }
                AggOp::Sum { value } => {
                    writeln!(out, "  {} partials[2] = {{({})0, ({})0}}; unsigned long long midpoint = input_counts[{port}] / 2ULL;", spec.ty.cuda(), spec.ty.cuda(), spec.ty.cuda()).unwrap();
                    writeln!(out, "  for (unsigned int part = 0; part < 2U; ++part) {{ unsigned long long begin = part == 0U ? 0ULL : midpoint; unsigned long long end = part == 0U ? midpoint : input_counts[{port}]; for (unsigned long long row = begin; row < end; ++row) {{").unwrap();
                    let selected = if let Some(filter) = &spec.agg.filter {
                        self.render(
                            filter,
                            Rows::Input {
                                box_index: spec.box_index,
                                port_index: spec.port_index,
                            },
                            Some(&Ty::Bool),
                            "state",
                            "row",
                        )?
                        .0
                    } else {
                        "1".to_owned()
                    };
                    let rendered = self
