                rhs: lhs_right,
            },
            Expr::Sub {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Mul {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Mul {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Div {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Div {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Eq {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Eq {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Ne {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Ne {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Lt {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Lt {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Le {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Le {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Gt {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Gt {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Ge {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Ge {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::And {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::And {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Or {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Or {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        ) => binary_expr_eq(lhs_left, lhs_right, rhs_left, rhs_right),
        (Expr::Not { expr: lhs }, Expr::Not { expr: rhs }) => expr_structural_eq(lhs, rhs),
        (
            Expr::EnumIs {
                attr: lhs_attr,
                variant: lhs_variant,
            },
            Expr::EnumIs {
                attr: rhs_attr,
                variant: rhs_variant,
            },
        ) => lhs_attr == rhs_attr && lhs_variant == rhs_variant,
        (
            Expr::Input {
                port: lhs_port,
                agg: lhs_agg,
            },
            Expr::Input {
                port: rhs_port,
                agg: rhs_agg,
            },
        ) => lhs_port == rhs_port && aggregate_structural_eq(lhs_agg, rhs_agg),
        (
            Expr::Agg {
                op: lhs_op,
                table: lhs_table,
                on: lhs_on,
                filter: lhs_filter,
            },
            Expr::Agg {
                op: rhs_op,
                table: rhs_table,
                on: rhs_on,
                filter: rhs_filter,
            },
        ) => {
            lhs_table == rhs_table
                && lhs_on == rhs_on
                && agg_op_structural_eq(lhs_op, rhs_op)
                && expr_structural_eq(lhs_filter, rhs_filter)
        }
        _ => false,
    }
}

#[derive(Clone, Debug, PartialEq)]
enum Accumulator {
    Int(Vec<i64>),
    Real(Vec<f64>),
}

#[derive(Clone, Debug)]
struct CacheEntry {
    key: AggregateKey,
    values: Accumulator,
}

/// Aggregate accumulators bound to one validated model and tick input scope.
///
/// Holding these references prevents allocator address reuse while entries are
/// live. A fresh cache is required for each snapshot/parameter scope.
#[derive(Clone, Debug)]
pub struct AggCache<'tick, 'state> {
    model: &'tick ValidatedModel,
    snapshot: &'tick Snapshot<'state>,
    params: &'tick ParamEnv,
    entries: Vec<CacheEntry>,
    build_count: usize,
}

impl<'tick, 'state> AggCache<'tick, 'state> {
    pub fn new(
        model: &'tick ValidatedModel,
        snapshot: &'tick Snapshot<'state>,
        params: &'tick ParamEnv,
    ) -> Self {
        Self {
            model,
            snapshot,
            params,
            entries: Vec::new(),
            build_count: 0,
        }
    }

    /// Returns the exact tick-start snapshot bound to this cache.
    pub fn snapshot(&self) -> &'tick Snapshot<'state> {
        self.snapshot
    }

    /// Number of structurally distinct aggregate accumulators currently held.
    pub fn len(&self) -> usize {
        self.entries.len()
    }

    pub fn is_empty(&self) -> bool {
        self.entries.is_empty()
    }

    /// Successful accumulator builds in this tick scope.
    pub fn build_count(&self) -> usize {
        self.build_count
    }

    /// Drops every accumulator while retaining the same tick scope.
    pub fn clear(&mut self) {
        self.entries.clear();
        self.build_count = 0;
    }

    fn validate_scope(
        &self,
        table: EvalTable<'_>,
        snapshot: &Snapshot<'_>,
        params: &ParamEnv,
    ) -> Result<(), EvalError> {
        if !std::ptr::eq(self.model, table.model) {
            return Err(EvalError::new(
                "aggregate cache belongs to a different model",
            ));
        }
        if !std::ptr::eq(self.snapshot, snapshot) {
            return Err(EvalError::new(
                "aggregate cache belongs to a different Snapshot object",
            ));
        }
        if !std::ptr::eq(self.params, params) {
            return Err(EvalError::new(
                "aggregate cache belongs to a different parameter environment",
            ));
        }
        Ok(())
    }
}

/// A deterministic evaluation failure.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct EvalError {
    message: String,
}

impl EvalError {
    fn new(message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
        }
    }
}

impl fmt::Display for EvalError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(&self.message)
    }
}

impl Error for EvalError {}

impl From<StateError> for EvalError {
    fn from(error: StateError) -> Self {
        Self::new(error.to_string())
    }
}

