fn infer_agg_op(
    op: &AggOp,
    model: &Model,
    model_box: &Box,
    row_attrs: &[Attr],
    path: &str,
) -> Result<ValueType, ValidationError> {
    match op {
        AggOp::Count => Ok(ValueType::Int),
