        return Err(EvalError::new("aggregate filter did not evaluate to Bool"));
    };

    // Level-A schedule shared with CUDA. Each half preserves ascending target
    // row order; merging always evaluates partial 0 before partial 1.
    let midpoint = filter.len() / 2;
