                .into_iter()
                .enumerate()
            {
                for row in range {
                    if filter[row] {
                        let group = snapshot.reference(
                            target.box_name(),
                            target.table_name(),
                            &on.fk_attr,
                            row,
                        )? as usize;
                        partials[partial][group] =
                            partials[partial][group].checked_add(1).ok_or_else(|| {
                                EvalError::new(format!("aggregate Count overflow in group {group}"))
                            })?;
                    }
                }
            }
