                .iter()
                .zip(&partials[1])
                .enumerate()
                .map(|(group, (left, right))| {
                    left.checked_add(*right).ok_or_else(|| {
                        EvalError::new(format!(
                            "aggregate Count overflow while merging group {group}"
                        ))
                    })
                })
