            Ok(Accumulator::Int(groups))
        }
        AggOp::Sum { value } => {
            let values = eval_expr(
                value,
                target,
                &target.schema().attrs,
                snapshot,
                params,
                cache,
                None,
            )?;
            match values {
                InternalColumn::Int(values) => {
                    let mut partials = [vec![0_i64; group_count], vec![0_i64; group_count]];
                    for (partial, range) in [0..midpoint, midpoint..filter.len()]
                        .into_iter()
                        .enumerate()
                    {
                        for row in range {
                            if filter[row] {
                                let group = snapshot.reference(
                                    target.box_name(),
                                    target.table_name(),
                                    &on.fk_attr,
                                    row,
                                )? as usize;
                                partials[partial][group] = partials[partial][group]
                                    .checked_add(values[row])
                                    .ok_or_else(|| {
                                        EvalError::new(format!(
                                            "integer Sum overflow in group {group}"
                                        ))
                                    })?;
                            }
                        }
                    }
                    let groups = partials[0]
                        .iter()
                        .zip(&partials[1])
                        .enumerate()
                        .map(|(group, (left, right))| {
                            left.checked_add(*right).ok_or_else(|| {
                                EvalError::new(format!(
                                    "integer Sum overflow while merging group {group}"
                                ))
                            })
                        })
                        .collect::<Result<Vec<_>, _>>()?;
                    Ok(Accumulator::Int(groups))
                }
                InternalColumn::Real(values) => {
                    let mut partials = [vec![0.0_f64; group_count], vec![0.0_f64; group_count]];
                    for (partial, range) in [0..midpoint, midpoint..filter.len()]
                        .into_iter()
                        .enumerate()
                    {
                        for row in range {
                            if filter[row] {
                                let group = snapshot.reference(
                                    target.box_name(),
                                    target.table_name(),
                                    &on.fk_attr,
                                    row,
                                )? as usize;
                                partials[partial][group] += values[row];
                            }
                        }
                    }
                    Ok(Accumulator::Real(
                        partials[0]
                            .iter()
                            .zip(&partials[1])
                            .map(|(left, right)| left + right)
                            .collect(),
                    ))
                }
                _ => Err(EvalError::new("Sum value did not evaluate to numeric")),
            }
        }
    }
}

