   1	//! Deterministic, snapshot-only evaluation of validated IR expressions.
   2	//!
   3	//! Expressions are evaluated in syntax-tree order without reassociation. Real
   4	//! arithmetic therefore uses ordinary IEEE-754 `f64` semantics: in particular,
   5	//! division by zero produces infinity or NaN rather than a runtime error.
   6	//! Aggregate sums make one sequential target-table pass in ascending row order;
   7	//! that order is the canonical Level A CPU reduction order (`DESIGN.md` §5.2).
   8	
   9	use std::error::Error;
  10	use std::fmt;
 935	fn eval_input_aggregate(
 936	    input: &InputTable,
 937	    agg: &Aggregate,
 938	    params: &ParamEnv,
 939	    result_rows: usize,
 940	    result_type: &RuntimeType,
 941	) -> Result<InternalColumn, EvalError> {
 942	    let mut selected = Vec::with_capacity(input.row_count);
 943	    for row in 0..input.row_count {
 944	        let keep = match &agg.filter {
 945	            Some(filter) => match eval_input_scalar(filter, input, row, params)? {
 946	                InputScalar::Bool(value) => value,
 947	                _ => return Err(EvalError::new("input aggregate filter is not Bool")),
 948	            },
 949	            None => true,
 950	        };
 951	        selected.push(keep);
 952	    }
 953	    match &agg.op {
 954	        AggOp::Count => {
 955	            let count = selected.iter().filter(|value| **value).count();
 956	            let count = i64::try_from(count)
 957	                .map_err(|_| EvalError::new("input aggregate count exceeds i64"))?;
 958	            Ok(InternalColumn::Int(vec![count; result_rows]))
 959	        }
 960	        AggOp::Sum { value } => {
 961	            // Level-A schedule shared with CUDA: ascending rows in two fixed
 962	            // contiguous halves, then partial 0 followed by partial 1.
 963	            let midpoint = input.row_count / 2;
 964	            match result_type {
 965	                RuntimeType::Real => {
 966	                    let mut partials = [0.0_f64; 2];
 967	                    for (partial, range) in [0..midpoint, midpoint..input.row_count]
 968	                        .into_iter()
 969	                        .enumerate()
 970	                    {
 971	                        for row in range {
 972	                            if !selected[row] {
 973	                                continue;
 974	                            }
 975	                            match eval_input_scalar(value, input, row, params)? {
 976	                                InputScalar::Int(value) => partials[partial] += value as f64,
 977	                                InputScalar::Real(value) => partials[partial] += value,
 978	                                _ => {
 979	                                    return Err(EvalError::new(
 980	                                        "input aggregate Sum value is not numeric",
 981	                                    ))
 982	                                }
 983	                            }
 984	                        }
 985	                    }
 986	                    Ok(InternalColumn::Real(vec![
 987	                        partials[0] + partials[1];
 988	                        result_rows
 989	                    ]))
 990	                }
 991	                RuntimeType::Int => {
 992	                    let mut partials = [0_i64; 2];
 993	                    for (partial, range) in [0..midpoint, midpoint..input.row_count]
 994	                        .into_iter()
 995	                        .enumerate()
 996	                    {
 997	                        for row in range {
 998	                            if !selected[row] {
 999	                                continue;
1000	                            }
1001	                            let InputScalar::Int(value) =
1002	                                eval_input_scalar(value, input, row, params)?
1003	                            else {
1004	                                return Err(EvalError::new(
1005	                                    "input aggregate Sum value is not numeric",
1006	                                ));
1007	                            };
1008	                            partials[partial] =
1009	                                partials[partial].checked_add(value).ok_or_else(|| {
1010	                                    EvalError::new(format!(
1011	                                        "input aggregate integer overflow at row {row}"
1012	                                    ))
1013	                                })?;
1014	                        }
1015	                    }
1016	                    let sum = partials[0].checked_add(partials[1]).ok_or_else(|| {
1017	                        EvalError::new("input aggregate integer overflow while merging partials")
1018	                    })?;
1019	                    Ok(InternalColumn::Int(vec![sum; result_rows]))
1020	                }
1021	                _ => Err(EvalError::new("input aggregate Sum has non-numeric type")),
1022	            }
1023	        }
1024	    }
1025	}
