1514	fn build_aggregate(
1515	    op: &AggOp,
1516	    target_name: &str,
1517	    on: &AggJoin,
1518	    filter: &Expr,
1519	    query: EvalTable<'_>,
1520	    snapshot: &Snapshot<'_>,
1521	    params: &ParamEnv,
1522	    cache: &mut AggCache<'_, '_>,
1523	) -> Result<Accumulator, EvalError> {
1524	    let target = query.target(target_name)?;
1525	    let target_fk = find_attr(&target.schema().attrs, &on.fk_attr)?;
1526	    let AttrType::Ref { table: group_table } = &target_fk.ty else {
1527	        return Err(EvalError::new("aggregate target join is not Ref-typed"));
1528	    };
1529	    let group_count = snapshot.row_count(query.box_name(), group_table)?;
1530	    let filter = eval_expr(
1531	        filter,
1532	        target,
1533	        &target.schema().attrs,
1534	        snapshot,
1535	        params,
1536	        cache,
1537	        Some(&RuntimeType::Bool),
1538	    )?;
1539	    let InternalColumn::Bool(filter) = filter else {
1540	        return Err(EvalError::new("aggregate filter did not evaluate to Bool"));
1541	    };
1542	
1543	    // Level-A schedule shared with CUDA. Each half preserves ascending target
1544	    // row order; merging always evaluates partial 0 before partial 1.
1545	    let midpoint = filter.len() / 2;
1546	    match op {
1547	        AggOp::Count => {
1548	            let mut partials = [vec![0_i64; group_count], vec![0_i64; group_count]];
1549	            for (partial, range) in [0..midpoint, midpoint..filter.len()]
1550	                .into_iter()
1551	                .enumerate()
1552	            {
1553	                for row in range {
1554	                    if filter[row] {
1555	                        let group = snapshot.reference(
1556	                            target.box_name(),
1557	                            target.table_name(),
1558	                            &on.fk_attr,
1559	                            row,
1560	                        )? as usize;
1561	                        partials[partial][group] =
1562	                            partials[partial][group].checked_add(1).ok_or_else(|| {
1563	                                EvalError::new(format!("aggregate Count overflow in group {group}"))
1564	                            })?;
1565	                    }
1566	                }
1567	            }
1568	            let groups = partials[0]
1569	                .iter()
1570	                .zip(&partials[1])
1571	                .enumerate()
1572	                .map(|(group, (left, right))| {
1573	                    left.checked_add(*right).ok_or_else(|| {
1574	                        EvalError::new(format!(
1575	                            "aggregate Count overflow while merging group {group}"
1576	                        ))
1577	                    })
1578	                })
1579	                .collect::<Result<Vec<_>, _>>()?;
1580	            Ok(Accumulator::Int(groups))
1581	        }
1582	        AggOp::Sum { value } => {
1583	            let values = eval_expr(
1584	                value,
1585	                target,
1586	                &target.schema().attrs,
1587	                snapshot,
1588	                params,
1589	                cache,
1590	                None,
1591	            )?;
1592	            match values {
1593	                InternalColumn::Int(values) => {
1594	                    let mut partials = [vec![0_i64; group_count], vec![0_i64; group_count]];
1595	                    for (partial, range) in [0..midpoint, midpoint..filter.len()]
1596	                        .into_iter()
1597	                        .enumerate()
1598	                    {
1599	                        for row in range {
1600	                            if filter[row] {
1601	                                let group = snapshot.reference(
1602	                                    target.box_name(),
1603	                                    target.table_name(),
1604	                                    &on.fk_attr,
1605	                                    row,
1606	                                )? as usize;
1607	                                partials[partial][group] = partials[partial][group]
1608	                                    .checked_add(values[row])
1609	                                    .ok_or_else(|| {
1610	                                        EvalError::new(format!(
1611	                                            "integer Sum overflow in group {group}"
1612	                                        ))
1613	                                    })?;
1614	                            }
1615	                        }
1616	                    }
1617	                    let groups = partials[0]
1618	                        .iter()
1619	                        .zip(&partials[1])
1620	                        .enumerate()
1621	                        .map(|(group, (left, right))| {
1622	                            left.checked_add(*right).ok_or_else(|| {
1623	                                EvalError::new(format!(
1624	                                    "integer Sum overflow while merging group {group}"
1625	                                ))
1626	                            })
1627	                        })
1628	                        .collect::<Result<Vec<_>, _>>()?;
1629	                    Ok(Accumulator::Int(groups))
1630	                }
1631	                InternalColumn::Real(values) => {
1632	                    let mut partials = [vec![0.0_f64; group_count], vec![0.0_f64; group_count]];
1633	                    for (partial, range) in [0..midpoint, midpoint..filter.len()]
1634	                        .into_iter()
1635	                        .enumerate()
1636	                    {
1637	                        for row in range {
1638	                            if filter[row] {
1639	                                let group = snapshot.reference(
1640	                                    target.box_name(),
1641	                                    target.table_name(),
1642	                                    &on.fk_attr,
1643	                                    row,
1644	                                )? as usize;
1645	                                partials[partial][group] += values[row];
1646	                            }
1647	                        }
1648	                    }
1649	                    Ok(Accumulator::Real(
1650	                        partials[0]
1651	                            .iter()
1652	                            .zip(&partials[1])
1653	                            .map(|(left, right)| left + right)
1654	                            .collect(),
1655	                    ))
1656	                }
1657	                _ => Err(EvalError::new("Sum value did not evaluate to numeric")),
1658	            }
1659	        }
1660	    }
1661	}
